		}
	}
	nextNewAssign := dispatch.AssignsLen

	for orderIdx := range oris {
		shipID := total_ship + orderIdx
		bestAssign := -1
		bestDelta := math.MaxFloat64

		candidates := availableIdx
		if len(candidates) == 0 {
			candidates = []int{}
		}
		for _, idx := range candidates {
			oldCost := dispatch.Assigns[idx].Cost
			if oldCost < 0 {
				continue
			}
			ok := dispatch.Assigns[idx].AddShip(shipID, oris[orderIdx], dess[orderIdx])
			if ok {
				dispatch.Assigns[idx].GenRoute()
				newCost := dispatch.Assigns[idx].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if delta < bestDelta {
						bestDelta = delta
						bestAssign = idx
					}
				}
			}
			dispatch.Assigns[idx].RemoveShip(shipID)
			dispatch.Assigns[idx].GenRoute()
		}

		if bestAssign >= 0 {
			dispatch.Assigns[bestAssign].AddShip(shipID, oris[orderIdx], dess[orderIdx])
			dispatch.Assigns[bestAssign].GenRoute()
			availableIdx = append(availableIdx, bestAssign)
			continue
		}

		fallbackUsed := false
		for tryIdx := nextNewAssign; tryIdx < MAXASSIGNS; tryIdx++ {
			ok := dispatch.Assigns[tryIdx].AddShip(shipID, oris[orderIdx], dess[orderIdx])
			if ok {
				dispatch.Assigns[tryIdx].GenRoute()
				if dispatch.Assigns[tryIdx].Cost >= 0 {
