			marginal := a.Cost - oldC
			if marginal < bestCand.newCost-bestCand.oldCost || bestCand.idx == -1 {
				bestCand.idx = ai
				bestCand.newCost = a.Cost
				bestCand.oldCost = oldC
				bestCand.isNew = false
				bestCand.addOK = true
			}
			a.RemoveShip(shipID)
			a.GenRoute()
